// Media type attachment identifier.
// Ref: #/components/schemas/FileMediaType
type FileMediaType string

const (
	FileMediaTypeFile  FileMediaType = "file"
	FileMediaTypeImage FileMediaType = "image"
	FileMediaTypeVideo FileMediaType = "video"
	FileMediaTypeAudio FileMediaType = "audio"
)

// AllValues returns all FileMediaType values.
func (FileMediaType) AllValues() []FileMediaType {
	return []FileMediaType{
		FileMediaTypeFile,
		FileMediaTypeImage,
		FileMediaTypeVideo,
		FileMediaTypeAudio,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s FileMediaType) MarshalText() ([]byte, error) {
	switch s {
	case FileMediaTypeFile:
		return []byte(s), nil
	case FileMediaTypeImage:
		return []byte(s), nil
	case FileMediaTypeVideo:
		return []byte(s), nil
	case FileMediaTypeAudio:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *FileMediaType) UnmarshalText(data []byte) error {
	switch FileMediaType(data) {
	case FileMediaTypeFile:
		*s = FileMediaTypeFile
		return nil
	case FileMediaTypeImage:
		*s = FileMediaTypeImage
		return nil
	case FileMediaTypeVideo:
		*s = FileMediaTypeVideo
		return nil
	case FileMediaTypeAudio:
		*s = FileMediaTypeAudio
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

